// Tampon + signature scannés du représentant légal RFC (Henri AIT-AZZOUZ).
// Embarqué dans le code comme fallback par défaut : tous les PDFs générés
// en sont déjà munis sans avoir à uploader quoi que ce soit dans /parametres.
// Écrasable plus tard via Parametres.tamponSignatureUrl si le signataire ou
// la version du tampon change.
//
// Format : JPEG 1538×600px, données embarquées en base64 data URI.
// PNG transparent serait préférable pour incrustation parfaite, mais le fond
// clair de cette version est compatible avec les fonds blancs des templates.
export const TAMPON_BASE64 = "data:image/jpeg;base64,";
